const api = async (tabela, metodo = "GET", corpo = null, query = "") => {
  const url = `${SUPABASE_URL}/rest/v1/${tabela}${query}`;
  const headers = {
    "apikey": SUPABASE_KEY,
    "Authorization": `Bearer ${SUPABASE_KEY}`,
    "Content-Type": "application/json",
  };
  if (metodo === "POST") headers["Prefer"] = "return=representation";
  if (metodo === "PATCH") headers["Prefer"] = "return=representation";
  const res = await fetch(url, { method: metodo, headers, body: corpo ? JSON.stringify(corpo) : null });
  if (!res.ok) { const e = await res.text(); console.error("API erro:", e); return []; }
  const txt = await res.text();
  return txt ? JSON.parse(txt) : [];
};

