// ============================================================
// COMPONENTES BASE
// ============================================================
function Badge({ tipo, texto }) {
  const mapa = { Ativo: "badge-verde", Inadimplente: "badge-vermelho", Pendente: "badge-amarelo", Pago: "badge-verde", "Em Aberto": "badge-azul", Quitado: "badge-verde", Suspenso: "badge-cinza" };
  return <span className={`status-dot ${mapa[tipo] || "badge-cinza"}`}>{texto || tipo}</span>;
}

function Toast({ msg, onClose }) {
  useEffect(() => { if (msg) { const t = setTimeout(onClose, 3000); return () => clearTimeout(t); } }, [msg]);
  if (!msg) return null;
  return <div className="toast">✓ {msg}</div>;
}

function Modal({ titulo, onClose, children }) {
  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <span className="modal-titulo">{titulo}</span>
          <button className="btn-fechar" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">{children}</div>
      </div>
    </div>
  );
}

