// DASHBOARD
function Dashboard({ usuario }) {
  const [socios, setSocios] = useState([]);
  const [fundos, setFundos] = useState([]);
  const [emprestimos, setEmprestimos] = useState([]);
  const [contribuicoes, setContribuicoes] = useState([]);
  const [movs, setMovs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([DB.getSocios(), DB.getFundos(), DB.getEmprestimos(), DB.getContribuicoes(), DB.getMovimentacoes()])
      .then(([s, f, e, c, m]) => { setSocios(s||[]); setFundos(f||[]); setEmprestimos(e||[]); setContribuicoes(c||[]); setMovs(m||[]); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{textAlign:"center",padding:"80px",color:"var(--azul)"}}>⏳ Carregando dados...</div>;

  const totalFundos = fundos.reduce((a, f) => a + f.saldo, 0);
  const ativos = socios.filter(s => s.status === "Ativo").length;
  const inadimplentes = socios.filter(s => s.status === "Inadimplente").length;
  const empAbertos = emprestimos.filter(e => e.status === "Em Aberto");
  const totalEmprestado = empAbertos.reduce((a, e) => a + e.valor, 0);

  return (
    <div>
      <div className="page-header">
        <div className="page-titulo">Painel Geral</div>
        <div className="page-sub">Bem-vindo, {usuario.cargo} · {new Date().toLocaleDateString("pt-BR", { weekday: "long", day: "numeric", month: "long", year: "numeric" })}</div>
      </div>

      {/* Stats */}
      <div className="cards-grid cards-grid-4" style={{ marginBottom: 24 }}>
        {[
          { icone: "🏦", valor: fmt(totalFundos), label: "Total nos Fundos", badge: "badge-verde", badgeTxt: "6 fundos ativos" },
          { icone: "👥", valor: socios.length, label: "Sócios Cadastrados", badge: "badge-verde", badgeTxt: `${ativos} ativos` },
          { icone: "⚠️", valor: inadimplentes, label: "Inadimplentes", badge: inadimplentes > 0 ? "badge-vermelho" : "badge-verde", badgeTxt: inadimplentes > 0 ? "Atenção necessária" : "Tudo em dia" },
          { icone: "📋", valor: empAbertos.length, label: "Empréstimos Abertos", badge: "badge-azul", badgeTxt: fmt(totalEmprestado) },
        ].map((s, i) => (
          <div key={i} className="card card-stat">
            <div className="card-stat-icone">{s.icone}</div>
            <div className="card-stat-valor">{s.valor}</div>
            <div className="card-stat-label">{s.label}</div>
            <span className={`card-stat-badge ${s.badge}`}>{s.badgeTxt}</span>
          </div>
        ))}
      </div>

      <div className="cards-grid cards-grid-2" style={{ marginBottom: 24 }}>
        {/* Fundos */}
        <div className="card">
          <div style={{ fontWeight: 700, fontSize: 15, color: "var(--verde)", marginBottom: 16 }}>💰 Saldos dos Fundos</div>
          {fundos.map(f => (
            <div key={f.id} style={{ marginBottom: 14 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 5 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ width: 10, height: 10, borderRadius: "50%", background: f.cor }} />
                  <span style={{ fontSize: 13, fontWeight: 600 }}>{f.nome}</span>
                </div>
                <span style={{ fontSize: 13, fontFamily: "var(--mono)", fontWeight: 700, color: "var(--verde)" }}>{fmt(f.saldo)}</span>
              </div>
              <div className="progress-wrap">
                <div className="progress-fill" style={{ width: `${Math.min((f.saldo / f.meta) * 100, 100)}%`, background: f.cor }} />
              </div>
              <div style={{ fontSize: 10, color: "var(--cinza4)", marginTop: 3 }}>Meta: {fmt(f.meta)} · {Math.round((f.saldo / f.meta) * 100)}%</div>
            </div>
          ))}
        </div>

        {/* Movimentações recentes */}
        <div className="card">
          <div style={{ fontWeight: 700, fontSize: 15, color: "var(--verde)", marginBottom: 16 }}>📊 Movimentações Recentes</div>
          {movs.slice(-6).reverse().map((m, i) => (
            <div key={i} className="extrato-item">
              <div className={`extrato-tipo ${m.tipo === "Entrada" ? "extrato-entrada" : "extrato-saida"}`}>
                {m.tipo === "Entrada" ? "↓" : "↑"}
              </div>
              <div className="extrato-info">
                <div className="extrato-desc">{m.descricao}</div>
                <div className="extrato-data">{m.fundo} · {fmtData(m.data)}</div>
              </div>
              <div className={`extrato-valor ${m.tipo === "Entrada" ? "entrada-cor" : "saida-cor"}`}>
                {m.tipo === "Entrada" ? "+" : "-"}{fmt(m.valor)}
              </div>
            </div>
          ))}
          {movs.length === 0 && <div className="estado-vazio"><div className="estado-vazio-txt">Sem movimentações</div></div>}
        </div>
      </div>

      {/* Avisos */}
      {inadimplentes > 0 && (
        <div style={{ background: "#FFEBEE", border: "1px solid #FFCDD2", borderRadius: "var(--radius)", padding: "16px 20px", display: "flex", alignItems: "center", gap: 12 }}>
          <span style={{ fontSize: 22 }}>⚠️</span>
          <div>
            <div style={{ fontWeight: 700, color: "#C62828", fontSize: 14 }}>Atenção: {inadimplentes} sócio(s) inadimplente(s)</div>
            <div style={{ fontSize: 13, color: "#B71C1C", marginTop: 2 }}>Acesse o módulo de Sócios para verificar e tomar as providências necessárias.</div>
          </div>
        </div>
      )}
    </div>
  );
}

// SÓCIOS
function Socios() {
  const [socios, setSocios] = useState([]);
  const [busca, setBusca] = useState("");
  const [modal, setModal] = useState(false);
  const [toast, setToast] = useState("");
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ nome: "", cpf: "", telefone: "", atividade: "Pescador(a)", contribuicao_base: 100 });

  useEffect(() => { DB.getSocios().then(s => { setSocios(s||[]); setLoading(false); }); }, []);

  const filtrados = socios.filter(s => s.nome.toLowerCase().includes(busca.toLowerCase()) || s.cpf.includes(busca) || s.numero?.includes(busca));

  const salvar = async () => {
    if (!form.nome || !form.cpf) return;
    const prox = socios.length + 1;
    const novo = { ...form, status: "Ativo", data_entrada: hoje(), numero: String(prox).padStart(3, "0") };
    const res = await DB.addSocio(novo);
    if (res && res.length > 0) setSocios(prev => [...prev, res[0]]);
    setModal(false); setForm({ nome: "", cpf: "", telefone: "", atividade: "Pescador(a)", contribuicao_base: 100 });
    setToast("Sócio cadastrado com sucesso!");
  };

  const alterarStatus = async (id, novoStatus) => {
    await DB.updateSocio(id, { status: novoStatus });
    setSocios(prev => prev.map(s => s.id === id ? { ...s, status: novoStatus } : s));
    setToast("Status atualizado!");
  };

  return (
    <div>
      <div className="page-header">
        <div className="page-titulo">Sócios</div>
        <div className="page-sub">{socios.length} sócios cadastrados · {socios.filter(s => s.status === "Ativo").length} ativos</div>
      </div>

      <div className="card">
        <div className="toolbar">
          <div className="toolbar-titulo">Lista de Sócios</div>
          <div className="busca-wrap" style={{ width: 260 }}>
            <span className="busca-icone">🔍</span>
            <input className="busca-input" placeholder="Buscar por nome, CPF..." value={busca} onChange={e => setBusca(e.target.value)} />
          </div>
          <button className="btn-verde" onClick={() => setModal(true)}>+ Novo Sócio</button>
        </div>

        <div className="tabela-wrap">
          <table className="tabela">
            <thead>
              <tr>
                <th>Nº</th><th>Nome</th><th>CPF</th><th>Telefone</th><th>Atividade</th>
                <th>Contribuição</th><th>Entrada</th><th>Status</th><th>Ações</th>
              </tr>
            </thead>
            <tbody>
              {filtrados.map(s => (
                <tr key={s.id}>
                  <td><span style={{ fontFamily: "var(--mono)", fontWeight: 700, color: "var(--verde)", fontSize: 13 }}>{s.numero}</span></td>
                  <td><span style={{ fontWeight: 600 }}>{s.nome}</span></td>
                  <td><span style={{ fontFamily: "var(--mono)", fontSize: 12 }}>{s.cpf}</span></td>
                  <td>{s.telefone}</td>
                  <td>{s.atividade}</td>
                  <td><span style={{ fontFamily: "var(--mono)", fontWeight: 600 }}>{fmt(s.contribuicao_base)}</span></td>
                  <td>{fmtData(s.dataEntrada)}</td>
                  <td><Badge tipo={s.status} /></td>
                  <td>
                    <div style={{ display: "flex", gap: 6 }}>
                      {s.status !== "Ativo" && <button className="btn-sm btn-sm-verde" onClick={() => alterarStatus(s.id, "Ativo")}>Ativar</button>}
                      {s.status === "Ativo" && <button className="btn-sm btn-sm-vermelho" onClick={() => alterarStatus(s.id, "Inadimplente")}>⚠</button>}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filtrados.length === 0 && <div className="estado-vazio"><div className="estado-vazio-icone">👥</div><div className="estado-vazio-txt">Nenhum sócio encontrado</div></div>}
        </div>
      </div>

      {modal && (
        <Modal titulo="Cadastrar Novo Sócio" onClose={() => setModal(false)}>
          <div className="form-row">
            <div className="form-group" style={{ gridColumn: "1/-1" }}>
              <label className="form-label">Nome Completo *</label>
              <input className="form-input" value={form.nome} onChange={e => setForm({ ...form, nome: e.target.value })} placeholder="Nome completo do sócio" />
            </div>
            <div className="form-group">
              <label className="form-label">CPF *</label>
              <input className="form-input" value={form.cpf} onChange={e => setForm({ ...form, cpf: e.target.value })} placeholder="000.000.000-00" />
            </div>
            <div className="form-group">
              <label className="form-label">Telefone</label>
              <input className="form-input" value={form.telefone} onChange={e => setForm({ ...form, telefone: e.target.value })} placeholder="(00) 90000-0000" />
            </div>
            <div className="form-group">
              <label className="form-label">Atividade</label>
              <select className="form-select" value={form.atividade} onChange={e => setForm({ ...form, atividade: e.target.value })}>
                {["Pescador(a)", "Agricultor(a)", "Artesão/ã", "Comerciante", "Outro"].map(a => <option key={a}>{a}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Contribuição Base (R$)</label>
              <input className="form-input" type="number" value={form.contribuicaoBase} onChange={e => setForm({ ...form, contribuicaoBase: +e.target.value })} />
            </div>
          </div>
          <div className="btns-row">
            <button className="btn-outline" onClick={() => setModal(false)}>Cancelar</button>
            <button className="btn-verde" onClick={salvar}>Salvar Sócio</button>
          </div>
        </Modal>
      )}
      <Toast msg={toast} onClose={() => setToast("")} />
    </div>
  );
}

// CONTRIBUIÇÕES
function Contribuicoes() {
  const [contribs, setContribs] = useState([]);
  const [socios, setSocios] = useState([]);
  const [fundos, setFundos] = useState([]);
  const [modal, setModal] = useState(false);
  const [toast, setToast] = useState("");
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ socio_id: "", valor: 100, mes_referencia: "", data_pagamento: hoje() });

  useEffect(() => {
    Promise.all([DB.getContribuicoes(), DB.getSocios(), DB.getFundos()])
      .then(([c, s, f]) => { setContribs(c||[]); setSocios(s||[]); setFundos(f||[]); setLoading(false); });
  }, []);

  const totalPago = contribs.filter(c => c.status === "Pago").reduce((a, c) => a + c.valor, 0);
  const pendentes = contribs.filter(c => c.status === "Pendente").length;

  const registrar = async () => {
    if (!form.socio_id || !form.mes_referencia) return;
    const socio = socios.find(s => s.id === +form.socio_id);
    const recibo = "REC-" + String(contribs.length + 1).padStart(3, "0");
    const nova = { socio_id: +form.socio_id, socio_nome: socio?.nome || "", valor: +form.valor, mes_referencia: form.mes_referencia, data_pagamento: form.data_pagamento, status: "Pago", recibo };
    const res = await DB.addContribuicao(nova);
    if (res && res.length > 0) setContribs(prev => [res[0], ...prev]);
    // Atualizar saldo dos fundos (Tzedaká, Parnasá, Progresso recebem 1/2 cada)
    const metade = +form.valor / 2;
    for (const f of fundos.filter(f => [1,2,3].includes(f.id))) {
      await DB.updateFundo(f.id, { saldo: (f.saldo || 0) + metade });
    }
    setFundos(prev => prev.map(f => [1,2,3].includes(f.id) ? { ...f, saldo: (f.saldo||0) + metade } : f));
    await DB.addMovimentacao({ tipo: "Entrada", fundo: "Múltiplos", descricao: "Contribuição " + form.mes_referencia + " - " + (socio?.nome||""), valor: +form.valor, data: form.data_pagamento });
    setModal(false); setToast("Contribuição registrada! Recibo emitido.");
  };

  return (
    <div>
      <div className="page-header">
        <div className="page-titulo">Contribuições Mensais</div>
        <div className="page-sub">Controle de pagamentos e recibos</div>
      </div>

      <div className="cards-grid cards-grid-3" style={{ marginBottom: 24 }}>
        {[
          { icone: "✅", valor: fmt(totalPago), label: "Total Arrecadado", badge: "badge-verde" },
          { icone: "⏳", valor: pendentes, label: "Pagamentos Pendentes", badge: pendentes > 0 ? "badge-amarelo" : "badge-verde" },
          { icone: "🧾", valor: contribs.filter(c => c.status === "Pago").length, label: "Recibos Emitidos", badge: "badge-azul" },
        ].map((s, i) => (
          <div key={i} className="card card-stat">
            <div className="card-stat-icone">{s.icone}</div>
            <div className="card-stat-valor">{s.valor}</div>
            <div className="card-stat-label">{s.label}</div>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="toolbar">
          <div className="toolbar-titulo">Registro de Contribuições</div>
          <button className="btn-verde" onClick={() => setModal(true)}>+ Registrar Pagamento</button>
        </div>
        <div className="tabela-wrap">
          <table className="tabela">
            <thead>
              <tr><th>Recibo</th><th>Sócio</th><th>Mês Ref.</th><th>Valor</th><th>Data Pagto.</th><th>Status</th></tr>
            </thead>
            <tbody>
              {contribs.slice().reverse().map(c => (
                <tr key={c.id}>
                  <td><span style={{ fontFamily: "var(--mono)", fontSize: 12, color: "var(--cinza5)" }}>{c.recibo || "—"}</span></td>
                  <td><span style={{ fontWeight: 600 }}>{c.socio_nome}</span></td>
                  <td>{c.mes_referencia}</td>
                  <td><span style={{ fontFamily: "var(--mono)", fontWeight: 700 }}>{fmt(c.valor)}</span></td>
                  <td>{fmtData(c.data_pagamento)}</td>
                  <td><Badge tipo={c.status} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {modal && (
        <Modal titulo="Registrar Contribuição" onClose={() => setModal(false)}>
          <div className="form-group">
            <label className="form-label">Sócio *</label>
            <select className="form-select" value={form.socio_id} onChange={e => setForm({ ...form, socio_id: e.target.value })}>
              <option value="">Selecione o sócio...</option>
              {socios.map(s => <option key={s.id} value={s.id}>{s.numero} — {s.nome}</option>)}
            </select>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Mês de Referência *</label>
              <input className="form-input" value={form.mes_referencia} onChange={e => setForm({ ...form, mes_referencia: e.target.value })} placeholder="Ex: Março/2025" />
            </div>
            <div className="form-group">
              <label className="form-label">Valor (R$)</label>
              <input className="form-input" type="number" value={form.valor} onChange={e => setForm({ ...form, valor: e.target.value })} />
            </div>
          </div>
          <div className="form-group">
            <label className="form-label">Data do Pagamento</label>
            <input className="form-input" type="date" value={form.data_pagamento} onChange={e => setForm({ ...form, data_pagamento: e.target.value })} />
          </div>
          <div className="btns-row">
            <button className="btn-outline" onClick={() => setModal(false)}>Cancelar</button>
            <button className="btn-verde" onClick={registrar}>Registrar e Emitir Recibo</button>
          </div>
        </Modal>
      )}
      <Toast msg={toast} onClose={() => setToast("")} />
    </div>
  );
}

// EMPRÉSTIMOS
function Emprestimos() {
  const [emprestimos, setEmprestimos] = useState([]);
  const [socios, setSocios] = useState([]);
  const [fundos, setFundos] = useState([]);
  const [modal, setModal] = useState(false);
  const [toast, setToast] = useState("");
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ socio_id: "", fundo_id: "", valor: "", parcelas: 1, finalidade: "", data_solicitacao: hoje() });

  useEffect(() => {
    Promise.all([DB.getEmprestimos(), DB.getSocios(), DB.getFundos()])
      .then(([e, s, f]) => { setEmprestimos(e||[]); setSocios(s||[]); setFundos(f||[]); setLoading(false); });
  }, []);

  const aprovar = async () => {
    if (!form.socio_id || !form.fundo_id || !form.valor) return;
    const socio = socios.find(s => s.id === +form.socio_id);
    const fundo = fundos.find(f => f.id === +form.fundo_id);
    const valor_parcela = +(+form.valor / +form.parcelas).toFixed(2);
    const novo = { socio_id: +form.socio_id, fundo_id: +form.fundo_id, socio_nome: socio?.nome, fundo_nome: fundo?.nome, valor: +form.valor, parcelas: +form.parcelas, valor_parcela, parcelas_pagas: 0, finalidade: form.finalidade, data_solicitacao: form.data_solicitacao, data_aprovacao: hoje(), status: "Em Aberto" };
    const res = await DB.addEmprestimo(novo);
    if (res && res.length > 0) setEmprestimos(prev => [res[0], ...prev]);
    await DB.updateFundo(+form.fundo_id, { saldo: Math.max(0, (fundo?.saldo||0) - +form.valor) });
    setFundos(prev => prev.map(f => f.id === +form.fundo_id ? { ...f, saldo: Math.max(0, (f.saldo||0) - +form.valor) } : f));
    await DB.addMovimentacao({ tipo: "Saída", fundo: fundo?.nome, descricao: "Empréstimo - " + socio?.nome, valor: +form.valor, data: hoje() });
    setModal(false); setToast("Empréstimo aprovado e registrado!");
  };

  const pagarParcela = async (emp) => {
    const novas = (emp.parcelas_pagas||0) + 1;
    const novoStatus = novas >= emp.parcelas ? "Quitado" : "Em Aberto";
    await DB.updateEmprestimo(emp.id, { parcelas_pagas: novas, status: novoStatus });
    setEmprestimos(prev => prev.map(e => e.id === emp.id ? { ...e, parcelas_pagas: novas, status: novoStatus } : e));
    const fundo = fundos.find(f => f.id === emp.fundo_id);
    await DB.updateFundo(emp.fundo_id, { saldo: (fundo?.saldo||0) + emp.valor_parcela });
    setFundos(prev => prev.map(f => f.id === emp.fundo_id ? { ...f, saldo: (f.saldo||0) + emp.valor_parcela } : f));
    setToast("Parcela registrada!");
  };

  return (
    <div>
      <div className="page-header">
        <div className="page-titulo">Empréstimos</div>
        <div className="page-sub">Controle de empréstimos e devoluções</div>
      </div>

      <div className="cards-grid cards-grid-3" style={{ marginBottom: 24 }}>
        {[
          { icone: "📋", valor: emprestimos.filter(e => e.status === "Em Aberto").length, label: "Em Aberto", badge: "badge-azul" },
          { icone: "💰", valor: fmt(emprestimos.filter(e => e.status === "Em Aberto").reduce((a, e) => a + e.valor, 0)), label: "Total Emprestado", badge: "badge-amarelo" },
          { icone: "✅", valor: emprestimos.filter(e => e.status === "Quitado").length, label: "Quitados", badge: "badge-verde" },
        ].map((s, i) => (
          <div key={i} className="card card-stat">
            <div className="card-stat-icone">{s.icone}</div>
            <div className="card-stat-valor">{s.valor}</div>
            <div className="card-stat-label">{s.label}</div>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="toolbar">
          <div className="toolbar-titulo">Controle de Empréstimos</div>
          <button className="btn-verde" onClick={() => setModal(true)}>+ Novo Empréstimo</button>
        </div>
        <div className="tabela-wrap">
          <table className="tabela">
            <thead>
              <tr><th>Sócio</th><th>Fundo</th><th>Valor</th><th>Parcelas</th><th>Pagas</th><th>Vr. Parcela</th><th>Finalidade</th><th>Status</th><th>Ação</th></tr>
            </thead>
            <tbody>
              {emprestimos.map(e => (
                <tr key={e.id}>
                  <td><span style={{ fontWeight: 600 }}>{e.socio_nome}</span></td>
                  <td><span style={{ fontSize: 12, background: "var(--cinza2)", padding: "3px 8px", borderRadius: 6, fontWeight: 600 }}>{e.fundo_nome}</span></td>
                  <td><span style={{ fontFamily: "var(--mono)", fontWeight: 700 }}>{fmt(e.valor)}</span></td>
                  <td style={{ textAlign: "center" }}>{e.parcelas}</td>
                  <td>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{ fontFamily: "var(--mono)", fontSize: 13 }}>{e.parcelas_pagas}/{e.parcelas}</span>
                      <div className="progress-wrap" style={{ width: 60 }}>
                        <div className="progress-fill" style={{ width: `${(e.parcelas_pagas / e.parcelas) * 100}%`, background: "var(--verde3)" }} />
                      </div>
                    </div>
                  </td>
                  <td><span style={{ fontFamily: "var(--mono)" }}>{fmt(e.valor_parcela)}</span></td>
                  <td style={{ maxWidth: 160, fontSize: 12, color: "var(--cinza5)" }}>{e.finalidade}</td>
                  <td><Badge tipo={e.status} /></td>
                  <td>
                    {e.status === "Em Aberto" && (
                      <button className="btn-sm btn-sm-verde" onClick={() => pagarParcela(e)}>+ Parcela</button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {emprestimos.length === 0 && <div className="estado-vazio"><div className="estado-vazio-icone">📋</div><div className="estado-vazio-txt">Nenhum empréstimo registrado</div></div>}
        </div>
      </div>

      {modal && (
        <Modal titulo="Registrar Empréstimo" onClose={() => setModal(false)}>
          <div className="form-group">
            <label className="form-label">Sócio *</label>
            <select className="form-select" value={form.socio_id} onChange={e => setForm({ ...form, socio_id: e.target.value })}>
              <option value="">Selecione...</option>
              {socios.filter(s => s.status === "Ativo").map(s => <option key={s.id} value={s.id}>{s.numero} — {s.nome}</option>)}
            </select>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Fundo *</label>
              <select className="form-select" value={form.fundo_id} onChange={e => setForm({ ...form, fundo_id: e.target.value })}>
                <option value="">Selecione o fundo...</option>
                {fundos.map(f => <option key={f.id} value={f.id}>{f.nome} ({fmt(f.saldo)})</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Valor (R$) *</label>
              <input className="form-input" type="number" value={form.valor} onChange={e => setForm({ ...form, valor: e.target.value })} placeholder="0,00" />
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label className="form-label">Nº de Parcelas</label>
              <select className="form-select" value={form.parcelas} onChange={e => setForm({ ...form, parcelas: e.target.value })}>
                {[1,2,3,4,5,6,8,10,12].map(n => <option key={n} value={n}>{n}x de {form.valor ? fmt(form.valor / n) : "—"}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Data da Solicitação</label>
              <input className="form-input" type="date" value={form.data_solicitacao} onChange={e => setForm({ ...form, data_solicitacao: e.target.value })} />
            </div>
          </div>
          <div className="form-group">
            <label className="form-label">Finalidade *</label>
            <input className="form-input" value={form.finalidade} onChange={e => setForm({ ...form, finalidade: e.target.value })} placeholder="Descreva o uso do recurso..." />
          </div>
          <div className="btns-row">
            <button className="btn-outline" onClick={() => setModal(false)}>Cancelar</button>
            <button className="btn-verde" onClick={aprovar}>Aprovar e Registrar</button>
          </div>
        </Modal>
      )}
      <Toast msg={toast} onClose={() => setToast("")} />
    </div>
  );
}

// EXTRATO DOS FUNDOS
function Fundos() {
  const [fundos, setFundos] = useState([]);
  const [movs, setMovs] = useState([]);
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    Promise.all([DB.getFundos(), DB.getMovimentacoes()])
      .then(([f, m]) => { setFundos(f||[]); setMovs(m||[]); setLoading(false); });
  }, []);
  if (loading) return <div style={{textAlign:"center",padding:"60px",color:"var(--azul)"}}>⏳ Carregando...</div>;

  return (
    <div>
      <div className="page-header">
        <div className="page-titulo">Extrato dos Fundos</div>
        <div className="page-sub">Saldos e movimentações de todos os 6 fundos</div>
      </div>

      <div className="cards-grid cards-grid-3" style={{ marginBottom: 24 }}>
        {fundos.map(f => (
          <div key={f.id} className="fundo-card" style={{ background: f.cor }}>
            <div className="fundo-nome">{f.nome}</div>
            <div className="fundo-desc">{f.descricao}</div>
            <div className="fundo-saldo">{fmt(f.saldo)}</div>
            <div className="fundo-meta-bar">
              <div className="fundo-meta-fill" style={{ width: `${Math.min((f.saldo / f.meta) * 100, 100)}%` }} />
            </div>
            <div className="fundo-meta-txt">Meta: {fmt(f.meta)} · {Math.round((f.saldo / f.meta) * 100)}% atingido</div>
          </div>
        ))}
      </div>

      <div className="card">
        <div style={{ fontWeight: 700, fontSize: 16, color: "var(--verde)", marginBottom: 20 }}>
          📊 Histórico de Movimentações
          <span style={{ fontWeight: 400, fontSize: 13, color: "var(--cinza4)", marginLeft: 10 }}>Total de {movs.length} registros</span>
        </div>
        <div className="tabela-wrap">
          <table className="tabela">
            <thead>
              <tr><th>Data</th><th>Tipo</th><th>Fundo</th><th>Descrição</th><th>Valor</th></tr>
            </thead>
            <tbody>
              {movs.slice().reverse().map((m, i) => (
                <tr key={i}>
                  <td style={{ fontFamily: "var(--mono)", fontSize: 12 }}>{fmtData(m.data)}</td>
                  <td>
                    <span style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 12, fontWeight: 700, color: m.tipo === "Entrada" ? "var(--verde)" : "#C62828" }}>
                      {m.tipo === "Entrada" ? "↓ Entrada" : "↑ Saída"}
                    </span>
                  </td>
                  <td><span style={{ fontSize: 12, background: "var(--cinza2)", padding: "3px 8px", borderRadius: 6, fontWeight: 600 }}>{m.fundo}</span></td>
                  <td style={{ fontSize: 13 }}>{m.descricao}</td>
                  <td>
                    <span style={{ fontFamily: "var(--mono)", fontWeight: 700, color: m.tipo === "Entrada" ? "var(--verde)" : "#C62828" }}>
                      {m.tipo === "Entrada" ? "+" : "-"}{fmt(m.valor)}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {movs.length === 0 && <div className="estado-vazio"><div className="estado-vazio-icone">📊</div><div className="estado-vazio-txt">Sem movimentações registradas</div></div>}
        </div>
      </div>
    </div>
  );
}

// RELATÓRIOS
function Relatorios() {
  const [socios, setSocios] = useState([]);
  const [fundos, setFundos] = useState([]);
  const [emprestimos, setEmprestimos] = useState([]);
  const [contribuicoes, setContribuicoes] = useState([]);
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    Promise.all([DB.getSocios(), DB.getFundos(), DB.getEmprestimos(), DB.getContribuicoes()])
      .then(([s,f,e,c]) => { setSocios(s||[]); setFundos(f||[]); setEmprestimos(e||[]); setContribuicoes(c||[]); setLoading(false); });
  }, []);
  if (loading) return <div style={{textAlign:"center",padding:"60px",color:"var(--azul)"}}>⏳ Carregando relatório...</div>;

  const totalFundos = fundos.reduce((a, f) => a + f.saldo, 0);
  const totalEmprestado = emprestimos.filter(e => e.status === "Em Aberto").reduce((a, e) => a + e.valor, 0);
  const totalArrecadado = contribuicoes.filter(c => c.status === "Pago").reduce((a, c) => a + c.valor, 0);

  return (
    <div>
      <div className="page-header">
        <div className="page-titulo">Relatórios e Transparência</div>
        <div className="page-sub">Extrato público · {new Date().toLocaleDateString("pt-BR", { month: "long", year: "numeric" })}</div>
      </div>

      {/* Resumo executivo */}
      <div className="card" style={{ marginBottom: 24, borderLeft: "4px solid var(--verde)" }}>
        <div style={{ fontWeight: 800, fontSize: 17, color: "var(--verde)", marginBottom: 16 }}>📋 Resumo Executivo — Comunidade Progresso</div>
        <div className="cards-grid cards-grid-4">
          {[
            { label: "Total nos Fundos", valor: fmt(totalFundos), cor: "var(--verde)" },
            { label: "Total Arrecadado", valor: fmt(totalArrecadado), cor: "#1565C0" },
            { label: "Total Emprestado", valor: fmt(totalEmprestado), cor: "#E65100" },
            { label: "Sócios Ativos", valor: socios.filter(s => s.status === "Ativo").length + " / " + socios.length, cor: "var(--verde)" },
          ].map((s, i) => (
            <div key={i} style={{ textAlign: "center", padding: "12px", background: "var(--cinza1)", borderRadius: "var(--radius2)" }}>
              <div style={{ fontSize: 22, fontWeight: 800, color: s.cor, fontFamily: "var(--mono)" }}>{s.valor}</div>
              <div style={{ fontSize: 12, color: "var(--cinza4)", marginTop: 4, fontWeight: 500 }}>{s.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Por sócio */}
      <div className="card" style={{ marginBottom: 24 }}>
        <div style={{ fontWeight: 700, fontSize: 15, color: "var(--verde)", marginBottom: 16 }}>👥 Relatório por Sócio</div>
        <div className="tabela-wrap">
          <table className="tabela">
            <thead>
              <tr><th>Nº</th><th>Nome</th><th>Status</th><th>Total Contribuído</th><th>Empréstimos</th><th>Saldo Devedor</th><th>Situação</th></tr>
            </thead>
            <tbody>
              {socios.map(s => {
                const contribSocio = contribuicoes.filter(c => c.socio_id === s.id && c.status === "Pago").reduce((a, c) => a + c.valor, 0);
                const empSocio = emprestimos.filter(e => e.socio_id === s.id);
                const saldoDevedor = empSocio.filter(e => e.status === "Em Aberto").reduce((a, e) => a + (e.valor - e.parcelas_pagas * e.valor_parcela), 0);
                return (
                  <tr key={s.id}>
                    <td style={{ fontFamily: "var(--mono)", fontWeight: 700, color: "var(--verde)", fontSize: 13 }}>{s.numero}</td>
                    <td style={{ fontWeight: 600 }}>{s.nome}</td>
                    <td><Badge tipo={s.status} /></td>
                    <td style={{ fontFamily: "var(--mono)", fontWeight: 700, color: "var(--verde)" }}>{fmt(contribSocio)}</td>
                    <td style={{ textAlign: "center" }}>{empSocio.length}</td>
                    <td style={{ fontFamily: "var(--mono)", fontWeight: 700, color: saldoDevedor > 0 ? "#C62828" : "var(--verde)" }}>{fmt(saldoDevedor)}</td>
                    <td><Badge tipo={saldoDevedor > 0 ? "Em Aberto" : "Quitado"} texto={saldoDevedor > 0 ? "Devedor" : "Em dia"} /></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Por fundo */}
      <div className="card">
        <div style={{ fontWeight: 700, fontSize: 15, color: "var(--verde)", marginBottom: 16 }}>🏦 Relatório por Fundo</div>
        <div className="tabela-wrap">
          <table className="tabela">
            <thead>
              <tr><th>Fundo</th><th>Saldo Atual</th><th>Meta</th><th>% Atingido</th><th>Progresso</th></tr>
            </thead>
            <tbody>
              {fundos.map(f => {
                const pct = Math.min((f.saldo / f.meta) * 100, 100);
                return (
                  <tr key={f.id}>
                    <td>
                      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                        <div style={{ width: 12, height: 12, borderRadius: "50%", background: f.cor, flexShrink: 0 }} />
                        <span style={{ fontWeight: 700 }}>{f.nome}</span>
                      </div>
                      <div style={{ fontSize: 11, color: "var(--cinza4)", marginLeft: 20 }}>{f.descricao}</div>
                    </td>
                    <td style={{ fontFamily: "var(--mono)", fontWeight: 800, color: f.cor }}>{fmt(f.saldo)}</td>
                    <td style={{ fontFamily: "var(--mono)", color: "var(--cinza5)" }}>{fmt(f.meta)}</td>
                    <td style={{ fontFamily: "var(--mono)", fontWeight: 700 }}>{Math.round(pct)}%</td>
                    <td style={{ width: 140 }}>
                      <div className="progress-wrap">
                        <div className="progress-fill" style={{ width: `${pct}%`, background: f.cor }} />
                      </div>
                    </td>
                  </tr>
                );
              })}
              <tr style={{ background: "var(--verdeC)" }}>
                <td style={{ fontWeight: 800, color: "var(--verde)" }}>TOTAL GERAL</td>
                <td style={{ fontFamily: "var(--mono)", fontWeight: 800, color: "var(--verde)" }}>{fmt(totalFundos)}</td>
                <td style={{ fontFamily: "var(--mono)", fontWeight: 700 }}>{fmt(fundos.reduce((a, f) => a + f.meta, 0))}</td>
                <td style={{ fontFamily: "var(--mono)", fontWeight: 700 }}>{Math.round((totalFundos / fundos.reduce((a, f) => a + f.meta, 0)) * 100)}%</td>
                <td></td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

// ============================================================
// APP PRINCIPAL
// ============================================================
export default function App() {
  const [usuario, setUsuario] = useState(null);
  const [pagina, setPagina] = useState("dashboard");
  const [email, setEmail] = useState("");
  const [senha, setSenha] = useState("");
  const [erro, setErro] = useState("");
  const [menuAberto, setMenuAberto] = useState(false);

  // Supabase — sem inicialização local necessária

  const login = async () => {
    setErro("Verificando...");
    const user = await DB.getUsuario(email, senha);
    if (user) { setUsuario(user); setErro(""); }
    else setErro("E-mail ou senha incorretos.");
  };

  const navItems = [
    { id: "dashboard", icone: "🏠", label: "Painel Geral" },
    { id: "socios", icone: "👥", label: "Sócios" },
    { id: "contribuicoes", icone: "💵", label: "Contribuições" },
    { id: "emprestimos", icone: "📋", label: "Empréstimos" },
    { id: "fundos", icone: "🏦", label: "Extrato dos Fundos" },
    { id: "relatorios", icone: "📊", label: "Relatórios" },
  ];

  const paginas = { dashboard: <Dashboard usuario={usuario || {}} />, socios: <Socios />, contribuicoes: <Contribuicoes />, emprestimos: <Emprestimos />, fundos: <Fundos />, relatorios: <Relatorios /> };

  if (!usuario) return (
    <>
      <style>{estilos}</style>
      <div className="login-wrap">
        <div className="login-card">
          <div className="login-logo">
            <img src="data:image/png;base64," alt="Logo Comunidade Progresso" style={{width:"200px",marginBottom:"16px",filter:"drop-shadow(0 2px 8px rgba(0,0,0,.12))"}}/>
            <p style={{fontSize:"12px",color:"var(--cinza4)",fontStyle:"italic",marginTop:"-4px"}}>“Fortalecer pessoas. Construir futuros.”</p>
          </div>
          {erro && <div className="erro-msg">⚠ {erro}</div>}
          <div className="campo-wrap">
            <label className="campo-label">E-MAIL DO DIRETOR</label>
            <input className="campo-input" type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="seu@email.com" onKeyDown={e => e.key === "Enter" && login()} />
          </div>
          <div className="campo-wrap">
            <label className="campo-label">SENHA</label>
            <input className="campo-input" type="password" value={senha} onChange={e => setSenha(e.target.value)} placeholder="••••••••" onKeyDown={e => e.key === "Enter" && login()} />
          </div>
          <button className="btn-primary" onClick={login}>Entrar no Sistema</button>
          <div style={{ marginTop: 20, background: "var(--cinza2)", borderRadius: 8, padding: "12px 14px" }}>
            <div style={{ fontSize: 11, fontWeight: 700, color: "var(--cinza5)", marginBottom: 6 }}>ACESSOS DE DEMONSTRAÇÃO</div>
            {[["presidente@comunidadeprogresso.org", "pres2025", "Presidente"],["financeiro@comunidadeprogresso.org", "fin2025", "Financeiro"],["operacoes@comunidadeprogresso.org", "op2025", "Operações"]].map(([e2, s2, c]) => (
              <div key={c} style={{ fontSize: 11, color: "var(--cinza5)", cursor: "pointer", padding: "3px 0" }} onClick={() => { setEmail(e2); setSenha(s2); }}>
                <span style={{ color: "var(--verde)", fontWeight: 600 }}>→ {c}:</span> {e2} / {s2}
              </div>
            ))}
          </div>
        </div>
      </div>
    </>
  );

  return (
    <>
      <style>{estilos}</style>
      <div className="app-layout">
        <button className="menu-toggle" onClick={() => setMenuAberto(!menuAberto)}>☰</button>
        <div className={`overlay-menu ${menuAberto ? "visivel" : ""}`} onClick={() => setMenuAberto(false)} />

        <aside className={`sidebar ${menuAberto ? "aberto" : ""}`}>
          <div className="sidebar-logo">
            <h2>Comunidade Progresso</h2>
            <p>Sistema FRS — v1.0</p>
          </div>
          <nav className="sidebar-nav">
            <div className="nav-label">Navegação</div>
            {navItems.map(n => (
              <button key={n.id} className={`nav-item ${pagina === n.id ? "ativo" : ""}`} onClick={() => { setPagina(n.id); setMenuAberto(false); }}>
                <span className="icone">{n.icone}</span>{n.label}
              </button>
            ))}
          </nav>
          <div className="sidebar-user">
            <div className="user-card">
              <div className="user-avatar">{usuario.avatar}</div>
              <div className="user-info">
                <div className="user-nome">{usuario.nome}</div>
                <div className="user-cargo">{usuario.cargo}</div>
              </div>
              <button className="btn-sair" onClick={() => setUsuario(null)} title="Sair">⏻</button>
            </div>
          </div>
        </aside>

        <main className="main-content">
          {paginas[pagina]}
        </main>
      </div>
    </>
  );
}
